from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

# Configure Redis connection
redis_nodes = [
    {"host": os.getenv("REDIS_NODE_1_HOST"), "port": os.getenv("REDIS_NODE_1_PORT")},
    {"host": os.getenv("REDIS_NODE_2_HOST"), "port": os.getenv("REDIS_NODE_2_PORT")},
]

redis_connections = [redis.StrictRedis(host=node["host"], port=node["port"], decode_responses=True) for node in redis_nodes]

def get_redis_connection():
    # Simple round-robin connection
    return redis_connections[0]  # For simplicity, using the first node

@app.route('/store_token', methods=['POST'])
def store_token():
    data = request.json
    token = data.get('token')
    ttl = data.get('ttl', 3600)  # Default TTL of 1 hour

    if not token:
        return jsonify({"error": "Token is required"}), 400

    conn = get_redis_connection()
    conn.setex(token, ttl, "stored")  # Store token with TTL
    return jsonify({"message": "Token stored successfully"}), 200

@app.route('/get_token/<token>', methods=['GET'])
def get_token(token):
    conn = get_redis_connection()
    value = conn.get(token)
    if value is None:
        return jsonify({"error": "Token not found"}), 404
    return jsonify({"token": token, "value": value}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)